import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";/* empty css                  */import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({navDepth:2,breadcrumbParent:{label:"Qatar Gold",url:"../../qatar.html"},countryCode:"QA",currency:"QAR",flag:"🇶🇦",nameEn:"Doha, Qatar",nameAr:"الدوحة، قطر",fixedPeg:!1,decimals:2,timezone:"Asia/Qatar",relatedCountries:[{file:"../../qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"../../uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"../../saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"../../kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"../../bahrain.html",nameEn:"Bahrain",nameAr:"البحرين",flag:"🇧🇭"}],faqEn:[{q:"What is the gold price in Doha today?",a:"The live gold price in Doha is shown above in Qatari Riyals (QAR) per gram, updated every 90 seconds. The QAR is pegged to USD at 3.64, so prices track global spot movements directly."},{q:"Is gold cheaper in Doha than in Dubai?",a:"The base spot price is similar across GCC markets — all peg to USD with close exchange rates. Minor differences arise from the exact peg rate (QAR at 3.64 vs AED at 3.6725 per USD). The main cost variables are making charges, VAT treatment, and shop margins."},{q:"Where is the best place to buy gold in Doha?",a:"Souq Waqif offers the most traditional experience with negotiable making charges. The Old Gold Souk area is good for local prices. Villaggio Mall and City Center offer branded chain retailers with fixed pricing. For investment gold, QNB and licensed banks are the safest option."},{q:"Is there VAT on gold purchases in Qatar?",a:"Qatar implemented VAT (initially 5%) which applies to most retail goods including jewellery. Investment-grade gold (bullion bars and coins) may qualify for different treatment. Always confirm the VAT treatment with the retailer at point of purchase and keep your receipt."}],faqAr:[{q:"ما هو سعر الذهب في الدوحة اليوم؟",a:"يُعرض سعر الذهب الحالي في الدوحة بالريال القطري (QAR) للغرام أعلاه، ويُحدَّث كل 90 ثانية. الريال القطري مرتبط بالدولار عند 3.64."},{q:"هل الذهب في الدوحة أرخص من دبي؟",a:"السعر الأساسي متقارب عبر أسواق الخليج لأنها جميعاً مرتبطة بالدولار. الفروق تأتي من أجرة الصنعة وضريبة القيمة المضافة وهوامش المحلات."},{q:"أين أفضل مكان لشراء الذهب في الدوحة؟",a:"سوق واقف يوفر أفضل تجربة تقليدية مع إمكانية التفاوض. منطقة الغانم القديمة جيدة للأسعار المحلية. أما البنوك المرخصة فهي الأنسب لشراء الذهب الاستثماري."}]});
